import cv2import numpy as npimport os# from some_code.image_process.file_process.move_file_compare import folderdef downsample_dataset(floder_path,save_path):    image_file_list = os.listdir(floder_path)    for i in range (len(image_file_list)):        image_path = os.path.join(floder_path,image_file_list[i])        image_array = cv2.imread(image_path)        downsampled_image = cv2.resize(image_array,dsize=None, fx=0.5, fy=0.5, interpolation=cv2.INTER_AREA)        image_save_path = os.path.join(save_path,image_file_list[i])        cv2.imwrite(image_save_path,downsampled_image)        print(f"downsampled image saved at {image_save_path} {i}/{len(image_file_list)}")if __name__ == '__main__':    folder = r"E:\project\Dataset\DIV2K_train_LR_bicubic\X2"    save_path = r"E:\project\Dataset\DIV2K_train_LR_bicubic\X4"    if not os.path.exists(save_path):        os.makedirs(save_path)    downsample_dataset(folder,save_path)